  4	import { S3Context } from '@odf/core/components/s3-browser/s3-context';
  5	import { getBucketOverviewBaseRoute } from '@odf/core/constants';
  6	import { S3ProviderType } from '@odf/core/types';
  7	import {
  8	  ButtonBar,
  9	  formSettings,
 10	  TextInputWithFieldRequirements,
 11	  useCustomTranslation,
 12	  useYupValidationResolver,
 13	} from '@odf/shared';
 14	import { LazyNameValueEditor } from '@odf/shared/utils/NameValueEditor';
 15	import cn from 'classnames';
 16	import * as _ from 'lodash-es';
 17	import { useForm } from 'react-hook-form';
 18	import { useNavigate } from 'react-router-dom-v5-compat';
 19	import {
 20	  ActionGroup,
 21	  Alert,
 22	  AlertVariant,
 23	  Button,
 24	  ButtonType,
 25	  ButtonVariant,
 26	  Form,
 27	  FormGroup,
 28	} from '@patternfly/react-core';
 29	import { TagIcon } from '@patternfly/react-icons';
 30	import './create-bucket-form.scss';
 31	
 32	type FormData = {
 33	  bucketName: string;
 34	};
 35	
 36	const CreateBucketForm: React.FC<{}> = () => {
 37	  const { t } = useCustomTranslation();
 38	  const navigate = useNavigate();
 39	  const [inProgress, setInProgress] = React.useState(false);
 40	  const [errorMessage, setErrorMessage] = React.useState('');
 41	  const [tagsData, setTagsData] = React.useState<string[][]>([]);
 42	
 43	  const { s3Client } = React.useContext(S3Context);
 44	  const providerType = s3Client.providerType as S3ProviderType;
 45	  const { bucketFormSchema, fieldRequirements } = useS3BucketFormValidation();
 46	  const resolver = useYupValidationResolver(bucketFormSchema);
 47	
 48	  const {
 49	    control,
 50	    handleSubmit,
 51	    formState: { isValid, isSubmitted },
 52	  } = useForm({
 53	    ...formSettings,
 54	    resolver,
 55	  });
 56	
 57	  const save = async (formData: FormData) => {
 58	    setInProgress(true);
 59	    setErrorMessage('');
 60	    const { bucketName } = formData;
 61	    try {
 62	      await s3Client.createBucket({ Bucket: bucketName });
 63	    } catch ({ name, message }) {
 64	      setErrorMessage(`Error while creating bucket: ${name}: ${message}`);
 65	      setInProgress(false);
 66	      return;
 67	    }
 68	
 69	    // Update bucket tags: any error here shouldn't prevent redirection
 70	    // as the bucket has been created successfully.
 71	    try {
 72	      const tagSet: PutBucketTaggingCommandInput['Tagging']['TagSet'] = tagsData
 73	        .filter((pair: string[]) => !_.isEmpty(pair[0]))
 74	        .map((pair: string[]) => ({ Key: pair[0], Value: pair[1] }));
 75	      if (!_.isEmpty(tagSet)) {
 76	        await s3Client.putBucketTags({
 77	          Bucket: bucketName,
 78	          Tagging: { TagSet: tagSet },
 79	        });
 80	      }
 81	    } catch ({ name, message }) {
 82	      // @TODO: add a toast warning that is visible after redirection to bucket details.
 83	      // eslint-disable-next-line no-console
 84	      console.error(`Error while updating bucket tags: ${name}: ${message}`);
 85	    }
 86	    navigate(`${getBucketOverviewBaseRoute(bucketName, providerType)}`);
 87	  };
 88	
 89	  return (
 90	    <Form onSubmit={handleSubmit(save)} className="pf-v6-u-w-50">
 91	      <TextInputWithFieldRequirements
 92	        control={control}
 93	        fieldRequirements={fieldRequirements}
 94	        popoverProps={{
 95	          headerContent: t('Name requirements'),
 96	          footerContent: `${t('Example')}: my-bucket`,
 97	        }}
 98	        formGroupProps={{
 99	          label: t('Bucket Name'),
100	          fieldId: 'bucket-name',
101	          isRequired: true,
102	          className: 'control-label',
103	        }}
104	        textInputProps={{
105	          id: 'bucket-name',
106	          name: 'bucketName',
107	          className: 'pf-v6-c-form-control',
108	          type: 'text',
109	          placeholder: t('my-bucket'),
110	          'aria-describedby': 'bucket-name-help',
111	          'data-test': 'bucket-name',
112	        }}
113	        helperText={t('A unique name for your bucket.')}
114	      />
115	      <FormGroup
116	        label={t('Tags')}
117	        labelInfo={t('Use different criteria for tagging your bucket.')}
118	        className={cn('odf-create-s3-bucket-form__tags', {
119	          'odf-create-s3-bucket-form__tags--empty': _.isEmpty(tagsData),
120	        })}
121	      >
122	        {_.isEmpty(tagsData) && (
123	          <div className="pf-v5-u-disabled-color-100 pf-v6-u-mr-sm">
124	            {t('No tags are attached to this bucket.')}
125	          </div>
126	        )}
127	        <LazyNameValueEditor
128	          className="pf-v6-u-font-weight-bold pf-v6-u-font-size-sm"
129	          addString={t('Add tag')}
130	          valueString={t('Value (optional)')}
131	          nameValuePairs={tagsData}
132	          updateParentData={({ nameValuePairs }) => {
133	            setTagsData(nameValuePairs);
134	          }}
135	          hideHeaderWhenNoItems={true}
136	          IconComponent={TagIcon}
137	          nameMaxLength={128}
138	          valueMaxLength={256}
139	        />
140	      </FormGroup>
141	      {!isValid && isSubmitted && (
142	        <Alert
143	          variant={AlertVariant.danger}
144	          isInline
145	          title={t('Address form errors to proceed')}
146	        />
147	      )}
148	      <ButtonBar errorMessage={errorMessage} inProgress={inProgress}>
149	        <ActionGroup className="pf-v6-c-form">
150	          <Button
151	            id="create-s3-bucket-btn"
152	            type={ButtonType.submit}
153	            variant={ButtonVariant.primary}
154	            data-test="obc-create"
155	          >
156	            {t('Create')}
157	          </Button>
158	          <Button
159	            onClick={() => navigate(-1)}
160	            type={ButtonType.button}
161	            variant={ButtonVariant.secondary}
162	          >
163	            {t('Cancel')}
164	          </Button>
165	        </ActionGroup>
166	      </ButtonBar>
167	    </Form>
168	  );
169	};
170	
171	export default CreateBucketForm;

